package edu.nd.pmcburne.hello

import com.google.gson.annotations.SerializedName
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

private const val BASE_URL = "https://www.cs.virginia.edu/"

private val retrofit = Retrofit.Builder()
    .addConverterFactory(GsonConverterFactory.create())
    .baseUrl(BASE_URL)
    .build()

interface PlacemarksService {
    @GET("~wxt4gm/placemarks.json")
    suspend fun getPlacemarks(): List<Location>
}

object PlacemarksAPI {
    val service: PlacemarksService by lazy {
        retrofit.create(PlacemarksService::class.java)
    }
}

class LocationRepository(
    private val dao: LocationDao,
    private val service: PlacemarksService
) {
    suspend fun syncLocationsIfNeeded() {
        if (dao.getLocationCount() == 0) {
            val locations = service.getPlacemarks()
            val entities = locations.map { location ->
                LocationEntity(
                    id = location.id,
                    name = location.name,
                    tags = location.tagList.joinToString(","),
                    description = location.description,
                    latitude = location.visualCenter.latitude,
                    longitude = location.visualCenter.longitude
                )
            }
            dao.upsertLocations(entities)
        }
    }

    suspend fun getLocationsByTag(tag: String) = dao.getLocationsByTag(tag)

    suspend fun getAllTags(): List<String> {
        return dao.getAllTags()
            .flatMap { it.split(",") }
            .map { it.trim() }
            .distinct()
            .sorted()
    }
}

data class Location(
    val id: Int,
    val name: String,
    @SerializedName("tag_list")
    val tagList: List<String>,
    val description: String,
    @SerializedName("visual_center")
    val visualCenter: VisualCenter
)

data class VisualCenter(
    val latitude: Double,
    val longitude: Double
)

